import{_ as e,o as a,c as r,aw as u}from"./chunks/framework.DLufY-ao.js";const o="/workbook/assets/queue.DACEl6db.png",p=JSON.parse('{"title":"Queue (Очередь)","description":"","frontmatter":{},"headers":[],"relativePath":"wiki/dev-commit/theory/data-structures/structures/queue.md","filePath":"wiki/dev-commit/theory/data-structures/structures/queue.md"}'),d={name:"wiki/dev-commit/theory/data-structures/structures/queue.md"};function i(l,t,s,c,n,h){return a(),r("div",null,[...t[0]||(t[0]=[u('<h1 id="queue-очередь" tabindex="-1">Queue (Очередь) <a class="header-anchor" href="#queue-очередь" aria-label="Permalink to &quot;Queue (Очередь)&quot;">​</a></h1><h2 id="информация" tabindex="-1">Информация <a class="header-anchor" href="#информация" aria-label="Permalink to &quot;Информация&quot;">​</a></h2><img src="'+o+'" width="300px"><div class="tip custom-block"><p class="custom-block-title">Queue</p><ul><li><p><strong>Queue (Очередь)</strong> - абстрактный тип данных с доступом к элементам, организованный по принципу <em>FIFO</em></p></li><li><p>Добавление элемента (<em>enqueue</em> — поставить в очередь) возможно лишь в конец очереди, выборка - только из начала очереди (<em>dequeue</em> - убрать из очереди), при этом выбранный элемент удаляется из очереди</p></li><li><p>Можно представить как очередь в продуктовом магазине: первым обслуживают того, кто пришёл в самом начале</p></li></ul></div><h2 id="операции" tabindex="-1">Операции <a class="header-anchor" href="#операции" aria-label="Permalink to &quot;Операции&quot;">​</a></h2><ul><li><code>enqueue</code> - добавлять элементы в конец очереди</li><li><code>dequeue</code> - удалять первый элемент из очереди</li></ul><h2 id="применение" tabindex="-1">Применение <a class="header-anchor" href="#применение" aria-label="Permalink to &quot;Применение&quot;">​</a></h2><ol><li>Очереди</li><li>Очередь событий JavaScript</li></ol><h2 id="сложность-алгоритма" tabindex="-1">Сложность алгоритма <a class="header-anchor" href="#сложность-алгоритма" aria-label="Permalink to &quot;Сложность алгоритма&quot;">​</a></h2><div class="tip custom-block"><p class="custom-block-title">Queue Priority Queue</p><ul><li><strong>Priority Queue</strong> (Очередь с приоритетом) - аналогично очереди, но output зависит от реализации: мы зададим ключ или параметр, по которому будет вычисляться приоритет output. Н-р: есть очередь задачь. когда закончена одна задача, переходим к следующей самой приоритетной из других</li></ul></div><p><strong>Временная сложность очереди</strong></p><table tabindex="0"><thead><tr><th>Алгоритм</th><th>Среднее значение</th><th>Худший случай</th></tr></thead><tbody><tr><td>Space</td><td>O(n)</td><td>O(n)</td></tr><tr><td>Search</td><td>O(n)</td><td>O(n)</td></tr><tr><td>Insert</td><td>O(1)</td><td>O(1)</td></tr><tr><td>Delete</td><td>O(1)</td><td>O(1)</td></tr></tbody></table>',12)])])}const _=e(d,[["render",i]]);export{p as __pageData,_ as default};
